const input = $input.first().json;

// Handle both string and object input from SFTP
let config;
if (typeof input === 'string') {
  try { config = JSON.parse(input); } catch {
    config = { version: null, categories: [] };
  }
} else if (input.data) {
  // Binary data
  try { config = JSON.parse(input.data.toString()); } catch {
    config = { version: null, categories: [] };
  }
} else {
  config = input;
}

// If no config or wrong version, use defaults
if (!config.version || config.version !== 3) {
  config = {
    version: 3,
    rotation: {
      enabled: true,
      order: [],
      adultSubRotation: ['hentai', 'japanese', 'amerika']
    },
    categories: []
  };
}

return { json: { config, categories: config.categories || [], rotation: config.rotation || {} } };

const formData = $input.first().json;
const configData = $('Parse Config').first().json;
const config = configData.config;

const action = formData.action || 'view';
const confirmed = formData.confirmed === true;

const result = {
  action,
  confirmed,
  formData,
  config,
  errors: [],
  warnings: []
};

// Validate based on action
switch (action) {
  case 'add':
    if (!formData.categoryId || !/^[a-z0-9_]{1,30}$/.test(formData.categoryId)) {
      result.errors.push({ field: 'categoryId', message: 'ID: alphanumeric + underscore, max 30 chars' });
    }
    if (!formData.gdriveFolderId) {
      result.errors.push({ field: 'gdriveFolderId', message: 'At least one GDrive folder ID required' });
    }
    if (config.categories.some(c => c.id === formData.categoryId)) {
      result.errors.push({ field: 'categoryId', message: `Category ID '${formData.categoryId}' already exists` });
    }
    if (config.categories.length >= 10) {
      result.errors.push({ field: 'categoryId', message: 'Maximum 10 categories reached' });
    }
    if (formData.categoryType === 'adult' && !formData.captions && formData.aiTranslate !== true) {
      result.warnings.push({ field: 'captions', message: 'Adult category with no captions and no AI translate — will use default' });
    }
    break;

  case 'edit':
  case 'delete':
  case 'enable':
  case 'disable':
    if (!formData.categoryId) {
      result.errors.push({ field: 'categoryId', message: 'Category ID required for this action' });
    } else {
      const exists = config.categories.some(c => c.id === formData.categoryId);
      if (!exists) {
        result.errors.push({ field: 'categoryId', message: `Category '${formData.categoryId}' not found` });
      }
      if (action === 'delete') {
        result.warnings.push({ field: 'categoryId', message: 'This will permanently delete the category from config' });
      }
    }
    break;

  case 'reorder':
    if (!formData.rotationOrder) {
      result.errors.push({ field: 'rotationOrder', message: 'Rotation order required (comma-separated IDs)' });
    } else {
      const ids = formData.rotationOrder.split(',').map(s => s.trim()).filter(Boolean);
      for (const id of ids) {
        if (!config.categories.some(c => c.id === id)) {
          result.errors.push({ field: 'rotationOrder', message: `Category '${id}' not found in config` });
        }
      }
    }
    break;

  case 'view':
    break;
}

return result;

const result = $('Detect Action').first().json;
const errors = result.errors || [];
const warnings = result.warnings || [];

const errorList = errors.map(e => `- **${e.field}**: ${e.message}`).join('\n');
const warningList = warnings.map(w => `- **${w.field}**: ${w.message}`).join('\n');

return {
  json: {
    status: 'error',
    errors,
    warnings,
    message: `Validation failed:\n\n${errorList}\n\n${warningList ? 'Warnings:\n' + warningList : ''}`
  }
};

const result = $('Detect Action').first().json;
const { action, confirmed, formData, config } = result;

if (!confirmed) {
  return { json: { status: 'preview', action, message: 'No changes made — confirmation was NO' } };
}

// Deep clone config
const newConfig = JSON.parse(JSON.stringify(config));

switch (action) {
  case 'add': {
    const newCategory = {
      id: formData.categoryId,
      name: formData.categoryName || formData.categoryId,
      type: formData.categoryType || 'standard',
      enabled: true,
      gdriveFolders: [{
        id: formData.gdriveFolderId,
        name: formData.gdriveFolderName || formData.categoryId
      }],
      collection: formData.collection || '',
      audience: formData.audience || 'paid',
      alwaysMembers: formData.alwaysMembers || false,
      price: parseInt(formData.price) || 10,
      captionSuffix: formData.captionSuffix || '',
      captions: formData.captions ? formData.captions.split('\n').map(s => s.trim()).filter(Boolean) : [],
      aiTranslate: formData.aiTranslate || false,
      aiPrompt: formData.aiPrompt || ''
    };

    if (newCategory.type === 'adult') {
      newCategory.subTypes = [{
        id: formData.categoryId + '_sub',
        name: newCategory.name,
        enabled: true,
        gdriveFolders: newCategory.gdriveFolders,
        collection: newCategory.collection,
        price: newCategory.price,
        aiTranslate: newCategory.aiTranslate
      }];
      // Override for adult
      newCategory.alwaysMembers = true;
    }

    newConfig.categories.push(newCategory);

    // Add to rotation order if not present
    if (!newConfig.rotation.order.includes(newCategory.id)) {
      newConfig.rotation.order.push(newCategory.id);
    }
    break;
  }

  case 'edit': {
    const idx = newConfig.categories.findIndex(c => c.id === formData.categoryId);
    if (idx >= 0) {
      const cat = newConfig.categories[idx];
      if (formData.categoryName) cat.name = formData.categoryName;
      if (formData.collection !== undefined) cat.collection = formData.collection;
      if (formData.audience) cat.audience = formData.audience;
      if (formData.alwaysMembers !== undefined) cat.alwaysMembers = formData.alwaysMembers;
      if (formData.price) cat.price = parseInt(formData.price);
      if (formData.captionSuffix !== undefined) cat.captionSuffix = formData.captionSuffix;
      if (formData.captions) {
        cat.captions = formData.captions.split('\n').map(s => s.trim()).filter(Boolean);
      }
      if (formData.aiTranslate !== undefined) cat.aiTranslate = formData.aiTranslate;
      if (formData.aiPrompt !== undefined) cat.aiPrompt = formData.aiPrompt;
      if (formData.gdriveFolderId) {
        cat.gdriveFolders = cat.gdriveFolders || [];
        cat.gdriveFolders.push({
          id: formData.gdriveFolderId,
          name: formData.gdriveFolderName || formData.gdriveFolderId
        });
      }
    }
    break;
  }

  case 'delete': {
    newConfig.categories = newConfig.categories.filter(c => c.id !== formData.categoryId);
    newConfig.rotation.order = newConfig.rotation.order.filter(id => id !== formData.categoryId);
    break;
  }

  case 'enable': {
    const cat = newConfig.categories.find(c => c.id === formData.categoryId);
    if (cat) cat.enabled = true;
    break;
  }

  case 'disable': {
    const cat = newConfig.categories.find(c => c.id === formData.categoryId);
    if (cat) cat.enabled = false;
    break;
  }

  case 'reorder': {
    newConfig.rotation.order = formData.rotationOrder
      .split(',')
      .map(s => s.trim())
      .filter(Boolean)
      .filter(id => newConfig.categories.some(c => c.id === id));
    break;
  }
}

// Ensure version
newConfig.version = 3;
newConfig.rotation = newConfig.rotation || { enabled: true, order: [], adultSubRotation: ['hentai', 'japanese', 'amerika'] };
newConfig.rotation.adultSubRotation = newConfig.rotation.adultSubRotation || ['hentai', 'japanese', 'amerika'];

return {
  json: {
    status: 'modified',
    action,
    newConfig,
    categoryCount: newConfig.categories.length
  }
};

const result = $('Apply Changes').first().json;
const pretty = JSON.stringify(result.newConfig, null, 2);

return {
  json: {
    status: result.status,
    action: result.action,
    categoryCount: result.categoryCount,
    preview: pretty.slice(0, 500) + (pretty.length > 500 ? '...' : ''),
    fullJson: pretty,
    message: result.status === 'preview'
      ? 'Preview only — no changes saved. Set "Confirm Action" to "Yes" to save.'
      : `Config modified: ${result.action}. Categories: ${result.categoryCount}.`
  }
};

const result = $('Apply Changes').first().json;
const pretty = JSON.stringify(result.newConfig, null, 2);

return {
  json: {
    json: result.newConfig,
    fileName: 'config.json',
    remotePath: `${$vars.VPS_UPLOAD_DIR}/config.json`
  }
};
